mapper.insert:
INSERT IGNORE INTO TB_ARTIST (
    ARTIST_NM
    , REG_TIME
) VALUES (
    #{artistNm}
    , NOW()
)

INSERT INTO TB_CONCERT_INFO (
    ARTIST_NM_KOR
    , ARTIST_NM_FOR
    , CONCERT_YEAR
    , CONCERT_MONTH
    , CONCERT_DATE
    , CONCERT_TIME
    , VENUE
    , TCT_SITE
    , TCT_OPEN_AT
    , EMAIL_YN
    , POP_SCORE
    , REG_TIME
) VALUES (
    #{artistNmKor}
    , #{artistNmFor}
    , #{concertYear}
    , #{concertMonth}
    , #{concertDate}
    , #{concertTime}
    , #{venue}
    , #{tctSite}
    , #{tctOpenAt}
    , #{emailYn}
    , #{popScore}
    , NOW()
)
ON DUPLICATE KEY UPDATE
    ARTIST_NM_KOR = VALUES(ARTIST_NM_KOR)
    , ARTIST_NM_FOR = VALUES(ARTIST_NM_FOR)
    , CONCERT_YEAR = VALUES(CONCERT_YEAR)
    , CONCERT_MONTH = VALUES(CONCERT_MONTH)
    , CONCERT_DATE = VALUES(CONCERT_DATE)
    , CONCERT_TIME = VALUES(CONCERT_TIME)
    , VENUE = VALUES(VENUE)
    , TCT_SITE = VALUES(TCT_SITE)
    , TCT_OPEN_AT = VALUES(TCT_OPEN_AT)

INSERT INTO TB_EMAIL_LOG (
    SUBJECT
    , EMAIL
    , REG_TIME
) VALUES (
    #{subject}
    , #{email}
    , NOW()
)

INSERT INTO TB_ARTIST_MSG (
    ARTIST_NM_KOR
    , CONCERT_YEAR
    , CONCERT_MONTH
    , CONCERT_DATE
    , SUBJECT
    , CONTENT
    , REG_TIME
) VALUES (
    #{artistNmKor}
    , #{concertYear}
    , #{concertMonth}
    , #{concertDate}
    , #{subject}
    , #{content}
    , NOW()
)

mapper.update:
UPDATE TB_ARTIST_MSG
   SET SEND_YN = 'Y'
 WHERE ARTIST_NM_KOR = #{artistNmKor}
   AND CONCERT_YEAR = #{concertYear}
   AND CONCERT_MONTH = #{concertMonth}
   AND CONCERT_DATE = #{concertDate}
